  centerPrint("Shake to record again", 430, 2, COLOR_MUTED);
}

// ================= WAV HEADER =====================
void writeWavHeader(File &file, uint32_t dataSize) {
  uint32_t chunkSize = 36 + dataSize;
  uint16_t audioFormat = 1;
  uint16_t numChannels = 1;
  uint32_t sampleRate = SAMPLE_RATE;
  uint16_t bitsPerSample = 16;
  uint32_t byteRate = sampleRate * numChannels * bitsPerSample / 8;
  uint16_t blockAlign = numChannels * bitsPerSample / 8;

  file.seek(0);
  file.write((const uint8_t*)"RIFF", 4);
  file.write((const uint8_t*)&chunkSize, 4);
  file.write((const uint8_t*)"WAVE", 4);
  file.write((const uint8_t*)"fmt ", 4);
  uint32_t subChunk1Size = 16;
  file.write((const uint8_t*)&subChunk1Size, 4);
  file.write((const uint8_t*)&audioFormat, 2);
  file.write((const uint8_t*)&numChannels, 2);
  file.write((const uint8_t*)&sampleRate, 4);
  file.write((const uint8_t*)&byteRate, 4);
  file.write((const uint8_t*)&blockAlign, 2);
  file.write((const uint8_t*)&bitsPerSample, 2);
  file.write((const uint8_t*)"data", 4);
  file.write((const uint8_t*)&dataSize, 4);
}

// ================= MIC INIT =======================
void MicInit() {
  i2s_config_t cfg = {
    .mode = (i2s_mode_t)(I2S_MODE_MASTER | I2S_MODE_RX),
    .sample_rate = SAMPLE_RATE,
    .bits_per_sample = I2S_BITS_PER_SAMPLE_16BIT,
    .channel_format = I2S_CHANNEL_FMT_ONLY_RIGHT,
    .communication_format = I2S_COMM_FORMAT_I2S,
    .intr_alloc_flags = ESP_INTR_FLAG_LEVEL1,
    .dma_buf_count = 8,      
    .dma_buf_len = 512,      
    .use_apll = true         
  };

  i2s_pin_config_t pin = {
    .bck_io_num = I2S_BCLK,
    .ws_io_num  = I2S_LRC,
    .data_out_num = I2S_PIN_NO_CHANGE,
    .data_in_num  = I2S_DIN
  };

  i2s_driver_install(I2S_NUM_0, &cfg, 0, NULL);
  i2s_set_pin(I2S_NUM_0, &pin);
}

// ================= START RECORD ===================
void startRecording() {
  char filename[32];
  sprintf(filename, "/rec_%03d.wav", recordingNumber);

  // Smart Indexing Check
  while(SD.exists(filename)) {
    recordingNumber++;
    sprintf(filename, "/rec_%03d.wav", recordingNumber);
  }

  recFile = SD.open(filename, FILE_WRITE);
  if(!recFile){
    drawBaseUI();
    centerPrint("ERROR", 200, 4, COLOR_DANGER);
    centerPrint("SD Card Write Failed", 250, 2, COLOR_TEXT);
    return;
  }

  for (int i=0;i<44;i++) recFile.write((uint8_t)0); // reserve header
  totalBytes = 0;
  isRecording = true;
  lastShake = millis(); // Reset debounce

  MicInit();
  drawRecordingUI();
}

// ================= STOP RECORD ====================
void stopRecording() {
  isRecording = false;
  i2s_driver_uninstall(I2S_NUM_0);
  writeWavHeader(recFile, totalBytes);
  recFile.close();

  char filename[32];
  sprintf(filename, "rec_%03d.wav", recordingNumber);
  drawSavedUI(String(filename));

  recordingNumber++; // Prepare for next
  lastShake = millis(); // Reset debounce
}

// ================= SETUP ==========================
void setup() {
  Serial.begin(115200);

  pinMode(TFT_BLK, OUTPUT);
  digitalWrite(TFT_BLK, LOW);


  gfx->begin();
  drawBaseUI();
  centerPrint("BOOTING...", 200, 2, COLOR_MUTED);

  SPI.begin(SD_SCK, SD_MISO, SD_MOSI, SD_CS);
  if (!SD.begin(SD_CS)) {
    centerPrint("SD FAIL", 250, 3, COLOR_DANGER);
    while(1);
  }

  // === SMART INDEXING ===
  drawBaseUI();
  centerPrint("INDEXING...", 200, 2, COLOR_MUTED);
  while(true) {
    char testName[32];
    sprintf(testName, "/rec_%03d.wav", recordingNumber);
    if (!SD.exists(testName)) {
      break; 
    }
    recordingNumber++;
  }

  if (!imu.begin(SDA, SCL)) {
    centerPrint("IMU FAIL", 250, 3, COLOR_DANGER);
    while(1);
  }

  imu.setAccelRange(QMI8658_ACCEL_RANGE_2G);
  imu.setAccelODR(QMI8658_ACCEL_ODR_500HZ);
  imu.setAccelUnit_mg(true);
  imu.enableSensors(QMI8658_ENABLE_ACCEL);

  drawBaseUI();
  centerPrint("Calibrating...", 200, 2, COLOR_MUTED);
  delay(1500);
  QMI8658_Data d;
  if (imu.readSensorData(d)) {
    lastAccelX = d.accelX;
    lastAccelY = d.accelY;
    lastAccelZ = d.accelZ;
  }
  imuCalibrated = true;

  drawStandbyUI();
}

// ================= LOOP ===========================
void loop() {
  uint8_t buffer[BUFFER_SIZE];
  size_t bytesRead;

  // ---------- RECORD DATA ----------
  if (isRecording) {
    // RAW Recording: No DSP, No Gain, No Loop Processing
    i2s_read(I2S_NUM_0, buffer, BUFFER_SIZE, &bytesRead, portMAX_DELAY);
    if (bytesRead > 0) {
      recFile.write(buffer, bytesRead);
      totalBytes += bytesRead;
    }
  }

  // ---------- SHAKE DETECT ----------
  if (imuCalibrated) {
    QMI8658_Data d;
    if (imu.readSensorData(d)) {
      float delta = abs(d.accelX - lastAccelX) + abs(d.accelY - lastAccelY) + abs(d.accelZ - lastAccelZ);
      lastAccelX = d.accelX;
      lastAccelY = d.accelY;
      lastAccelZ = d.accelZ;

      // START: Standard Threshold
      // STOP: Higher Threshold (Prevents accidental stops)
      int currentThreshold = isRecording ? SHAKE_THRESHOLD_STOP : SHAKE_THRESHOLD_START;

      if (delta > currentThreshold && millis() - lastShake > SHAKE_DEBOUNCE) {
        lastShake = millis();
        if (!isRecording) startRecording();
        else stopRecording();
      }
    }
  }
